using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.Collaboration{    /// <summary>    /// 协作服务    /// </summary>    public class CollaborationService    {        private readonly CollaborationManager _collaborationManager;                /// <summary>        /// 协作管理器        /// </summary>        public CollaborationManager CollaborationManager => _collaborationManager;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public CollaborationService(DesignContext context)        {            _collaborationManager = new CollaborationManager(context);        }    }}